interface LineItem {
  description: string;
  quantity: number;
  unitPrice: number;
  taxRate: number;
  discount?: { type: 'percentage' | 'fixed'; value: number };
}

interface InvoiceResult {
  lines: Array<{
    subtotal: number;
    discountAmount: number;
    taxableAmount: number;
    taxAmount: number;
    total: number;
  }>;
  subtotal: number;
  totalDiscount: number;
  totalTax: number;
  grandTotal: number;
}

function calculateInvoice(items: LineItem[]): InvoiceResult {
  const lines = items.map((item) => {
    // Calculate subtotal
    let subtotal = item.quantity * item.unitPrice;
    subtotal = Math.round(subtotal * 100) / 100;

    // Handle discount calculation - percentage or fixed amount
    let discountAmount = 0;
    if (item.discount) {
      discountAmount = item.discount.type === 'percentage' 
        ? (subtotal * item.discount.value) / 100 
        : item.discount.value;
      discountAmount = Math.round(discountAmount * 100) / 100;
      // Cap discount at subtotal to prevent negative amounts
      discountAmount = Math.min(discountAmount, subtotal);
