  const totalTax = Math.round(lines.reduce((sum, line) => sum + line.taxAmount, 0) * 100) / 100;
  const grandTotal = Math.round((subtotal - totalDiscount + totalTax) * 100) / 100;

  return { lines, subtotal, totalDiscount, totalTax, grandTotal };
}
